  ('elementary-f29af906-moex-00178', 'elementary-f29af906', 'elementary-f29af906-moex-114-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '有關「臺中市政府地政局所屬各地政事務所辦理跨所土地登記作業要點」之法律性質，下列敘述何者正確？', '["屬於行政程序法第159條規定之行政規則", "屬於地方制度法第29條規定為地方行政機關辦理上級機關委辦事項之委辦規則", "屬於地方制度法第31條規定為地方立法機關所訂定之自律規則", "屬於地方制度法第25條規定為地方立法機關所通過之自治條例"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "2422d4d20ab9", "answer_pdf_sha1": "1c183efc0748", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00179', 'elementary-f29af906', 'elementary-f29af906-moex-114-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '有關行政法上之事實行為，下列敘述何者正確？', '["所謂事實行為係指造成一定事實之改變而產生法律效力之得喪變更", "地政局對於不動產經紀業所為之政策性行政指導並非事實行為", "地政事務所所為之土地所有權移轉登記屬事實行為", "土地徵收公告後，登記機關於土地登記簿上註記徵收公告文號之行為，係事實行為"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "2422d4d20ab9", "answer_pdf_sha1": "1c183efc0748", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00180', 'elementary-f29af906', 'elementary-f29af906-moex-114-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '有關法律明確性原則之判斷標準，下列何者錯誤？', '["可理解性", "可預見性", "司法審查可能性", "可信賴性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "2422d4d20ab9", "answer_pdf_sha1": "1c183efc0748", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00181', 'elementary-f29af906', 'elementary-f29af906-moex-114-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依土地徵收條例之規定，區段徵收範圍內得規劃配設農業專用區，其規劃原則、申請配售資格、條件、面 積、作業程序及其他應遵行事項之辦法，由各級主管機關定之。有關該辦法之敘述，下列何者正確？', '["該辦法之內容應遵守「法律保留原則」", "該辦法之內容應遵守「量能優先性原則」", "該辦法之性質應屬於「作業性行政規則」", "該辦法之性質應屬於「裁量性行政規則」"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "2422d4d20ab9", "answer_pdf_sha1": "1c183efc0748", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00182', 'elementary-f29af906', 'elementary-f29af906-moex-114-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依行政程序法之規定，行政機關對於不特定人之送達，得以刊登政府公報或新聞紙代替之，此種送達方式 為下列何者？', '["公示送達", "公告送達", "寄存送達", "留置送達"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "2422d4d20ab9", "answer_pdf_sha1": "1c183efc0748", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00183', 'elementary-f29af906', 'elementary-f29af906-moex-114-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '人民於主管機關公告徵收後，意圖領取更多農作改良物補償費而為搶種作物之行為，違反下列何種行政法 上一般原理原則？', '["誠信原則", "信賴保護原則", "平等原則", "不當聯結禁止原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "2422d4d20ab9", "answer_pdf_sha1": "1c183efc0748", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00184', 'elementary-f29af906', 'elementary-f29af906-moex-114-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '有關行政程序法規定的聽證程序，下列敘述何者錯誤？', '["除法律另有規定外，應公開以言詞為之", "聽證，應作成聽證紀錄。聽證紀錄當場製作完成者，由陳述或發問人簽名或蓋章", "主持人認當事人意見業經充分陳述，而事件已達可為決定之程度者，應即終結聽證", "聽證終結後，決定作成前，主持人認為必要時，得再為聽證"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "2422d4d20ab9", "answer_pdf_sha1": "1c183efc0748", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00185', 'elementary-f29af906', 'elementary-f29af906-moex-114-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '苗栗縣頭份市公所為開闢都市計畫道路工程之需，依法申請徵收甲之土地，經核准徵收並依法公告後，甲 對其徵收處分不服，提起訴願。其訴願管轄機關為下列何者？', '["行政院", "內政部", "苗栗縣政府", "苗栗縣頭份市公所"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "2422d4d20ab9", "answer_pdf_sha1": "1c183efc0748", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00186', 'elementary-f29af906', 'elementary-f29af906-moex-114-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '有關耕地三七五減租條例規定之耕地租約涉訟，下列敘述何者錯誤？', '["對於主管機關所為有關耕地租約之登記，若有不服，應提起訴願、行政訴訟", "耕地租約屆滿時，出租人為維持其一家生活而收回耕地致承租人失其家庭生活依據，若有不服，應循序 提起民事訴訟", "耕地租約屆滿前，經依法編定或變更為非耕地使用，出租人得終止租約並須補償承租人，有關補償數額 之爭議，若有不服，應循序提民事訴訟", "關於耕地承租人違法轉租他人耕作，出租人主張耕地租約無效所生爭議，應提民事訴訟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "2422d4d20ab9", "answer_pdf_sha1": "1c183efc0748", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00187', 'elementary-f29af906', 'elementary-f29af906-moex-114-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依據行政訴訟法之規定，下列何者為確認桃園航空城特定區都市計畫違法訴訟之被告？', '["桃園市大園區公所", "桃園市政府", "內政部", "土地所有權人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "2422d4d20ab9", "answer_pdf_sha1": "1c183efc0748", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL)
